powershell -Command "
# Obsidian Local REST API (default port 27123)
\$obsidian = try { (Invoke-WebRequest -Uri 'http://localhost:27123' -TimeoutSec 2 -ErrorAction Stop).StatusCode } catch { \$_.Exception.Message }

# Check what's listening on common MCP/local ports
\$ports = @(27123, 27124, 3000, 8080, 11434)
foreach (\$p in \$ports) {
    \$conn = (Get-NetTCPConnection -LocalPort \$p -State Listen -ErrorAction SilentlyContinue)
    if (\$conn) { Write-Output \"LISTENING: \$p -> PID \$(\$conn.OwningProcess)\" }
}
" 2>&1

powershell -Command "
# Check running processes relevant to the swarm
\$relevant = @('obsidian', 'node', 'python', 'ollama', 'claude', 'code')
foreach (\$name in \$relevant) {
    \$procs = Get-Process -Name \$name -ErrorAction SilentlyContinue
    if (\$procs) {
        foreach (\$p in \$procs) {
            Write-Output \"\$(\$p.Name) | PID \$(\$p.Id) | Mem \$([math]::Round(\$p.WorkingSet64/1MB))MB\"
        }
    }
}
" 2>&1

powershell -Command "
# Identify which Obsidian PID owns port 27124 (MCP server)
\$conn = Get-NetTCPConnection -LocalPort 27124 -State Listen -ErrorAction SilentlyContinue
if (\$conn) {
    \$proc = Get-Process -Id \$conn.OwningProcess -ErrorAction SilentlyContinue
    Write-Output \"MCP port 27124 owner: \$(\$proc.Name) PID \$(\$proc.Id) Mem \$([math]::Round(\$proc.WorkingSet64/1MB))MB\"
}

# Quick HTTP probe of 27124
try {
    \$r = Invoke-WebRequest -Uri 'http://localhost:27124' -TimeoutSec 2 -ErrorAction Stop
    Write-Output \"27124 HTTP: \$(\$r.StatusCode)\"
} catch {
    Write-Output \"27124 HTTP: \$(\$_.Exception.Message)\"
}
" 2>&1
